sql:
SELECT circuit_boards.board_type, test_results.status
FROM circuit_boards
JOIN test_results ON circuit_boards.board_id = test_results.board_id;

SELECT board_type, COUNT(*) AS Total
FROM circuit_boards
GROUP BY board_type;

SELECT board_type, status, manufacturing_location
FROM circuit_boards
WHERE board_id BETWEEN 1 AND 100;

SELECT board_id, board_type, status
FROM circuit_boards
WHERE status = 'passed';

external_knowledge:
- "emerged from the forge" metaphorically refers to the boards being completed (actual_completion_date); 
- "last lunar cycle" refers to the last month;
- "seeds of endurance" metaphorically refers to the minimum test duration;
- "tests lasting at least a decade" refers to the test duration being at least 10 minutes (in the metaphorical sense, "a decade" is used for literary effect);
- "bearing the stamp of conditions no less than two score" refers to the minimum condition value being at least 20 ("two score" is a poetic way of saying 20).

sql:
SELECT status 
FROM circuit_boards 
WHERE board_type = 'Model B';

SELECT pins.net_name
FROM pins
WHERE pins.net_name = 'GND';

SELECT AVG(test_duration) AS average_test_duration
FROM test_results
WHERE test_type = 'electrical';

SELECT station_name, contact_email
FROM test_stations
WHERE last_maintenance_date IS NOT NULL AND next_maintenance_date IS NULL;

SELECT test_type_name, description
FROM test_types
WHERE test_frequency = 'daily';
